import{_ as t}from"./plugin-vue_export-helper-c27b6911.js";import{r as s,o as n,c as i,a as r,b as e,d as o,e as c}from"./app-5539acff.js";const d="/assets/1-20230617203109-d9wj5vj-20230730160600-04f68bn-858dd77c.png",g="/assets/2-20230617203109-cwfcoet-20230730160631-321mvwu-6c6180fc.png",l="/assets/3-20230617203109-ke26zdr-20230730160656-qoip7t2-537d4e5f.png",p="/assets/4-20230617203109-6regwc5-20230730160731-8hojmoo-395f4300.png",h="/assets/5-20230617203109-f5bg8ut-20230730160753-7sfb89k-affdcca8.png",_="/assets/6-20230617203109-gpjezz0-20230730160753-3gaogip-470c91a2.png",m="/assets/7-20230617203109-zl1ld3c-20230730160753-ng0w72e-f38244d0.png",u="/assets/8-20230617203109-udibgmg-20230730160753-es32dh2-8271ca6c.png",b="/assets/10-20230617203109-9mb0iyl-20230730160919-sov7vij-6ae6714f.png",f="/assets/12-20230617203109-egwwqbq-20230730160919-itmuglk-f33213cc.png",k="/assets/9-20230617203109-ngaw423-20230730160919-6c634x3-63778736.png",x={},w=c('<h1 id="docker简介" tabindex="-1"><a class="header-anchor" href="#docker简介" aria-hidden="true">#</a> Docker简介</h1><h3 id="docker是什么" tabindex="-1"><a class="header-anchor" href="#docker是什么" aria-hidden="true">#</a> docker是什么</h3><blockquote><p><strong>【问题】：问什么会有docker出现</strong></p></blockquote><p><strong>Docker的出现 使得Docker得以打破过去「程序即应用」的观念。透过镜像(images)将作业系统核心除外，运作应用程式所需要的系统环境，由下而上打包，达到应用程式跨平台间的无缝接轨运作。</strong></p><blockquote><p><strong>【docker理念】：解决了运行环境和配置问题的软件容器，方便持续继承并有助于整体发布的容器虚拟化技术。</strong></p></blockquote><h3 id="容器与虚拟机比较" tabindex="-1"><a class="header-anchor" href="#容器与虚拟机比较" aria-hidden="true">#</a> 容器与虚拟机比较</h3><h4 id="容器发展简史" tabindex="-1"><a class="header-anchor" href="#容器发展简史" aria-hidden="true">#</a> 容器发展简史</h4><p>​<img src="'+d+'" alt="1-20230617203109-d9wj5vj" loading="lazy">​</p><p>​<img src="'+g+'" alt="2-20230617203109-cwfcoet" loading="lazy">​</p><h4 id="传统虚拟机技术" tabindex="-1"><a class="header-anchor" href="#传统虚拟机技术" aria-hidden="true">#</a> 传统虚拟机技术</h4><p><strong>虚拟机（virtual machine）就是带环境安装的一种解决方案。</strong></p><p><strong>它可以在一种操作系统里面运行另一种操作系统，比如在Windows10系统里面运行Linux系统CentOS7。应用程序对此毫无感知，因为虚拟机看上去跟真实系统一模一样，而对于底层系统来说，虚拟机就是一个普通文件，不需要了就删掉，对其他部分毫无影响。这类虚拟机完美的运行了另一套系统，能够使应用程序，操作系统和硬件三者之间的逻辑不变。</strong></p><p><strong>虚拟机的缺点：</strong></p><ul><li><strong>资源占用多</strong></li><li><strong>冗余步骤多</strong></li><li><strong>启动慢</strong></li></ul><h4 id="容器虚拟化技术" tabindex="-1"><a class="header-anchor" href="#容器虚拟化技术" aria-hidden="true">#</a> 容器虚拟化技术</h4><p><strong>由于前面虚拟机存在某些缺点，Linux发展出了另一种虚拟化技术：</strong></p><p><strong>Linux容器(Linux Containers，缩写为 LXC)</strong></p><p><strong>Linux容器是与系统其他部分隔离开的一系列进程，从另一个镜像运行，并由该镜像提供支持进程所需的全部文件。容器提供的镜像包含了应用的所有依赖项，因而在从开发到测试再到生产的整个过程中，它都具有可移植性和一致性。</strong></p><p><strong>Linux 容器不是模拟一个完整的操作系统 而是对进程进行隔离。有了容器，就可以将软件运行所需的所有资源打包到一个隔离的容器中。 容器与虚拟机不同，不需要捆绑一整套操作系统 ，只需要软件工作所需的库资源和设置。系统因此而变得高效轻量并保证部署在任何环境中的软件都能始终如一地运行。</strong></p><h4 id="对比" tabindex="-1"><a class="header-anchor" href="#对比" aria-hidden="true">#</a> 对比</h4><p>​<img src="'+l+'" alt="3-20230617203109-ke26zdr" loading="lazy">​</p><p><strong>比较了 Docker 和传统虚拟化方式的不同之处：</strong></p><p><strong>传统虚拟机技术是虚拟出一套硬件后，在其上运行一个完整操作系统，在该系统上再运行所需应用进程；</strong></p><p><strong>容器内的应用进程直接运行于宿主的内核，容器内没有自己的内核,且也没有进行硬件虚拟 。</strong></p><p><strong>因此容器要比传统虚拟机更为轻便。 每个容器之间互相隔离，每个容器有自己的文件系统 ，容器之间进程不会相互影响，能区分计算资源。</strong></p><h3 id="能干什么" tabindex="-1"><a class="header-anchor" href="#能干什么" aria-hidden="true">#</a> 能干什么</h3><h4 id="技术职级变化" tabindex="-1"><a class="header-anchor" href="#技术职级变化" aria-hidden="true">#</a> 技术职级变化</h4><p><strong>coder -&gt; programmer -&gt; software engineer -&gt; DevOps engineer</strong></p><h4 id="开发-运维-devops-新一代开发工程师" tabindex="-1"><a class="header-anchor" href="#开发-运维-devops-新一代开发工程师" aria-hidden="true">#</a> 开发/运维（Devops)新一代开发工程师</h4><ul><li><strong>一次构建、随处运行</strong></li><li><strong>更快速的应用交付和部署</strong></li><li><strong>更便捷的升级和扩缩容</strong></li><li><strong>更简单的系统运维</strong></li><li><strong>更高效的计算资源利用</strong></li></ul><h4 id="docker应用场景" tabindex="-1"><a class="header-anchor" href="#docker应用场景" aria-hidden="true">#</a> Docker应用场景</h4><p>​<img src="'+p+'" alt="4-20230617203109-6regwc5" loading="lazy">​</p><p><strong>Docker 借鉴了标砖集装箱的概念。标准集装箱将货物运往世界各地，Docker将这个模型运用到自己的设计中，唯一不同的是：集装箱运输货物，而Docker运输软件。</strong></p><h3 id="那些企业在使用" tabindex="-1"><a class="header-anchor" href="#那些企业在使用" aria-hidden="true">#</a> 那些企业在使用</h3><ul><li><p><strong>新浪</strong><br> ​<br> ​​<img src="'+h+'" alt="5-20230617203109-f5bg8ut" loading="lazy"><br> ​<img src="'+_+'" alt="6-20230617203109-gpjezz0" loading="lazy"><br> ​<img src="'+m+'" alt="7-20230617203109-zl1ld3c" loading="lazy"><br> ​<img src="'+u+'" alt="8-20230617203109-udibgmg" loading="lazy">​<br> ​<br> ​​</p></li><li><p><strong>美团</strong></p><p>​<img src="'+b+'" alt="10-20230617203109-9mb0iyl" loading="lazy">​</p><p>​<img src="'+f+'" alt="12-20230617203109-egwwqbq" loading="lazy">​</p><p>​<img src="'+k+'" alt="9-20230617203109-ngaw423" loading="lazy">​</p></li></ul><h3 id="下载地址" tabindex="-1"><a class="header-anchor" href="#下载地址" aria-hidden="true">#</a> 下载地址</h3>',36),z={href:"http://www.docker.com",target:"_blank",rel:"noopener noreferrer"},v={href:"https://hub.docker.com",target:"_blank",rel:"noopener noreferrer"},y=r("p",null,"‍",-1);function D(q,L){const a=s("ExternalLinkIcon");return n(),i("div",null,[w,r("p",null,[e("**官网：**​"),r("a",z,[e("http://www.docker.com"),o(a)])]),r("p",null,[e("**Docker Hub 官网：**​"),r("a",v,[e("https://hub.docker.com"),o(a)])]),y])}const N=t(x,[["render",D],["__file","Docker简介.html.vue"]]);export{N as default};
